+import React, { useState } from 'react';
+import { Link, useLocation, useNavigate } from 'react-router-dom';
+import { useTheme } from '../context/ThemeContext';
+import { useAuth } from '../context/AuthContext';
+import { 
+  FiHome, FiShoppingCart, FiPackage, FiList, FiBarChart2, 
+  FiSun, FiMoon, FiMenu, FiX, FiLogOut, FiUser, FiBell, FiSettings,
+  FiUsers, FiPieChart
+} from 'react-icons/fi';
+
+const Layout = ({ children }) => {
+  const { darkMode, toggleDarkMode } = useTheme();
+  const { user, logout, isAdmin } = useAuth();
+  const location = useLocation();
+  const navigate = useNavigate();
+  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
+
+  const navItems = [
+    { path: '/dashboard', label: 'Dashboard', icon: FiHome },
+    { path: '/cashier', label: 'Cashier', icon: FiShoppingCart },
+    { path: '/products', label: 'Products', icon: FiPackage },
+    { path: '/inventory', label: 'Inventory', icon: FiList },
+    { path: '/sales', label: 'Sales', icon: FiBarChart2 },
+  ];
+
+  const adminNavItems = [
+    { path: '/admin', label: 'Admin Dashboard', icon: FiUsers },
+    { path: '/admin/cashiers', label: 'Cashiers', icon: FiUsers },
+    { path: '/admin/reports', label: 'Reports', icon: FiPieChart },
+  ];
+
+  const handleLogout = () => {
+    logout();
+    navigate('/login');
+  };
+
+  return (
+    <div className="min-h-screen flex flex-col" style={{ backgroundColor: '#F4F6F9' }}>
+      <header style={{ background: 'linear-gradient(135deg, #1E4FA3 0%, #2D6CDF 100%)' }} className="text-white shadow-md">
+        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
+          <div className="flex items-center justify-between h-16">
+            <div className="flex items-center">
+              <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center">
+                <FiUser size={18} />
+              </div>
+              <span className="ml-2 text-sm hidden md:block">{user?.name}</span>
+            </div>
+            <div className="flex items-center gap-2">
+              <FiShoppingCart size={24} />
+              <span className="text-xl font-bold">Grocery POS System</span>
+            </div>
+            <div className="flex items-center gap-3">
+              <button className="p-2 rounded-lg hover:bg-white/10 transition">
+                <FiBell size={20} />
+              </button>
+              <button className="p-2 rounded-lg hover:bg-white/10 transition">
+                <FiSettings size={20} />
+              </button>
+              <button
+                onClick={toggleDarkMode}
+                className="p-2 rounded-lg hover:bg-white/10 transition"
+              >
+                {darkMode ? <FiSun size={20} /> : <FiMoon size={20} />}
+              </button>
+              <button
+                onClick={handleLogout}
+                className="p-2 rounded-lg hover:bg-white/10 transition"
+                title="Logout"
+              >
+                <FiLogOut size={20} />
+              </button>
+            </div>
+          </div>
+        </div>
+      </header>
+
+      <nav className="hidden lg:block bg-white shadow-sm border-b border-gray-200">
+        <div className="max-w-7xl mx-auto px-4">
+          <div className="flex items-center gap-2 py-2">
+            {navItems.map(item => {
+              const Icon = item.icon;
+              const isActive = location.pathname === item.path;
+              return (
+                <Link
+                  key={item.path}
+                  to={item.path}
+                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
+                    isActive
+                      ? 'bg-blue-50 text-blue-700'
+                      : 'text-gray-700 hover:bg-gray-100'
+                  }`}
+                >
+                  <Icon size={18} />
+                  {item.label}
+                </Link>
+              );
+            })}
+            {isAdmin() && adminNavItems.map(item => {
+              const Icon = item.icon;
+              const isActive = location.pathname === item.path;
+              return (
+                <Link
+                  key={item.path}
+                  to={item.path}
+                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
+                    isActive
+                      ? 'bg-blue-50 text-blue-700'
+                      : 'text-gray-700 hover:bg-gray-100'
+                  }`}
+                >
+                  <Icon size={18} />
+                  {item.label}
+                </Link>
+              );
+            })}
+          </div>
+        </div>
+      </nav>
+
+      <div className="lg:hidden bg-white border-b border-gray-200 p-2">
+        <button
+          onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
+          className="flex items-center gap-2 px-3 py-2 rounded-lg hover:bg-gray-100"
+        >
+          {mobileMenuOpen ? <FiX size={20} /> : <FiMenu size={20} />}
+          <span>Menu</span>
+        </button>
+      </div>
+
+      {mobileMenuOpen && (
+        <div className="lg:hidden bg-white border-b border-gray-200 p-2">
+          {navItems.map(item => {
+            const Icon = item.icon;
+            const isActive = location.pathname === item.path;
+            return (
+              <Link
+                key={item.path}
+                to={item.path}
+                onClick={() => setMobileMenuOpen(false)}
+                className={`flex items-center gap-2 px-4 py-3 rounded-lg transition-colors ${
+                  isActive ? 'bg-blue-50 text-blue-700' : 'text-gray-700 hover:bg-gray-100'
+                }`}
+              >
+                <Icon size={18} />
+                {item.label}
+              </Link>
+            );
+          })}
+          {isAdmin() && adminNavItems.map(item => {
+            const Icon = item.icon;
+            const isActive = location.pathname === item.path;
+            return (
+              <Link
+                key={item.path}
+                to={item.path}
+                onClick={() => setMobileMenuOpen(false)}
+                className={`flex items-center gap-2 px-4 py-3 rounded-lg transition-colors ${
+                  isActive ? 'bg-blue-50 text-blue-700' : 'text-gray-700 hover:bg-gray-100'
+                }`}
+              >
+                <Icon size={18} />
+                {item.label}
+              </Link>
+            );
+          })}
+        </div>
+      )}
+
+      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-6">
+        {children}
+      </main>
+
+      <footer className="border-t border-gray-200 mt-auto py-4 text-center text-sm text-gray-500">
+        <div className="max-w-7xl mx-auto px-4">
+          © 2024 Grocery POS System. All rights reserved.
+        </div>
+      </footer>
+    </div>
+  );
+};
+
+export default Layout;
